sql:
SELECT COUNT(review_id) AS total_reviews
FROM reviews
WHERE patron_id = 1;

SELECT format_name, description
FROM formats
WHERE is_digital = 1;

SELECT COUNT(*) AS digital_formats_count
FROM formats
WHERE is_digital = 1;

SELECT publisher_name, contact_email
FROM publishers
WHERE is_active = 1;

SELECT subject_name
FROM resource_subjects
WHERE subject_name = 'Fiction';

SELECT COUNT(*) AS active_patrons_count
FROM patrons
WHERE is_active = 1;

SELECT usage_type
FROM resource_usage
WHERE ASINH(JULIANDAY(usage_date) - 2440587.5) > 0;

SELECT format_name, COUNT(*) AS format_count
FROM formats
GROUP BY format_name;

SELECT AVG(rating) AS average_rating
FROM reviews
WHERE resource_id = 1;
